INSERT INTO <Table> (<PrimaryKeyColumn>, <Column0>)
VALUES (<PrimaryKeyValue>, <Value0>)
ON CONFLICT(<PrimaryKeyColumn>) DO UPDATE SET <Column0>=excluded.<Column0>;

INSERT INTO <Table> (<PrimaryKeyColumn>, <Column0>, <Column1>)
VALUES (<PrimaryKeyValue>, <Value0>, <Value1>)
ON CONFLICT(<PrimaryKeyColumn>) DO UPDATE SET <Column0>=excluded.<Column0>, <Column1>=excluded.<Column1>;

INSERT INTO <Table> (<PrimaryKeyColumn>, <Column0>, <Column1>, <Column2>)
VALUES (<PrimaryKeyValue>, <Value0>, <Value1>, <Value2>)
ON CONFLICT(<PrimaryKeyColumn>) DO UPDATE SET <Column0>=excluded.<Column0>, <Column1>=excluded.<Column1>, <Column2>=excluded.<Column2>;
